import { User, UserRole, ServiceRequest, RequestStatus, JobApplication } from '../types';

const KEYS = {
  USERS: 'autogo_users',
  REQUESTS: 'autogo_requests',
  APPLICATIONS: 'autogo_applications',
  CURRENT_USER: 'autogo_current_user'
};

const DEFAULT_USERS: User[] = [
  { id: '1', name: 'Admin User', email: 'admin@autogo.com', role: UserRole.ADMIN },
  { id: '2', name: 'John Tech', email: 'tech@autogo.com', role: UserRole.TECHNICIAN },
  { id: '3', name: 'Mohamed Ahmed', email: 'mohamed@autogo.com', role: UserRole.CUSTOMER, isPro: true }
];

export const db = {
  init: () => {
    if (!localStorage.getItem(KEYS.USERS)) {
      localStorage.setItem(KEYS.USERS, JSON.stringify(DEFAULT_USERS));
    }
    if (!localStorage.getItem(KEYS.REQUESTS)) {
      localStorage.setItem(KEYS.REQUESTS, JSON.stringify([]));
    }
    if (!localStorage.getItem(KEYS.APPLICATIONS)) {
      localStorage.setItem(KEYS.APPLICATIONS, JSON.stringify([]));
    }
  },

  getUsers: (): User[] => JSON.parse(localStorage.getItem(KEYS.USERS) || '[]'),

  getRequests: (): ServiceRequest[] => JSON.parse(localStorage.getItem(KEYS.REQUESTS) || '[]'),

  addRequest: (request: Omit<ServiceRequest, 'id' | 'status' | 'createdAt'>) => {
    const requests = db.getRequests();
    const newRequest: ServiceRequest = {
      ...request,
      id: Math.random().toString(36).substr(2, 9),
      status: RequestStatus.PENDING,
      createdAt: new Date().toISOString()
    };
    requests.push(newRequest);
    localStorage.setItem(KEYS.REQUESTS, JSON.stringify(requests));
    return newRequest;
  },

  updateRequest: (id: string, updates: Partial<ServiceRequest>) => {
    const requests = db.getRequests();
    const index = requests.findIndex(r => r.id === id);
    if (index !== -1) {
      requests[index] = { ...requests[index], ...updates };
      localStorage.setItem(KEYS.REQUESTS, JSON.stringify(requests));
    }
  },

  getApplications: (): JobApplication[] => JSON.parse(localStorage.getItem(KEYS.APPLICATIONS) || '[]'),

  addApplication: (app: Omit<JobApplication, 'id' | 'status'>) => {
    const apps = db.getApplications();
    const newApp: JobApplication = {
      ...app,
      id: Math.random().toString(36).substr(2, 9),
      status: 'PENDING'
    };
    apps.push(newApp);
    localStorage.setItem(KEYS.APPLICATIONS, JSON.stringify(apps));
    return newApp;
  },

  getCurrentUser: (): User | null => {
    const user = localStorage.getItem(KEYS.CURRENT_USER);
    return user ? JSON.parse(user) : null;
  },

  setCurrentUser: (user: User | null) => {
    if (user) localStorage.setItem(KEYS.CURRENT_USER, JSON.stringify(user));
    else localStorage.removeItem(KEYS.CURRENT_USER);
  }
};

import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const diagnoseProblem = async (problemType: string, description: string) => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `User reports a ${problemType} issue with their car. Description: ${description}. 
                 Provide a short, professional, encouraging 'Smart Diagnosis' for a mobile mechanic dispatch. 
                 Mention potential causes and what the technician will likely check. Keep it under 100 words.`,
      config: {
        temperature: 0.7,
        topP: 0.8,
      }
    });
    return response.text || "Diagnostic data unavailable. A technician will perform a physical inspection on arrival.";
  } catch (error) {
    console.error("Gemini diagnosis failed", error);
    return "Technician will perform live diagnosis upon arrival.";
  }
};

import React, { useState, useEffect } from 'react';
import { User, UserRole } from './types';
import { db } from './services/db';
import Navbar from './components/Navbar';
import Home from './pages/Home';
import Login from './pages/Login';
import RequestService from './pages/RequestService';
import CustomerDashboard from './pages/CustomerDashboard';
import AdminDashboard from './pages/AdminDashboard';
import TechDashboard from './pages/TechDashboard';
import Careers from './pages/Careers';
import About from './pages/About';
import Contact from './pages/Contact';
import ServicesPage from './pages/ServicesPage';
import ProPlans from './pages/ProPlans';
import Footer from './components/Footer';

const App: React.FC = () => {
  const [currentPage, setCurrentPage] = useState<string>('home');
  const [user, setUser] = useState<User | null>(null);

  useEffect(() => {
    db.init();
    const savedUser = db.getCurrentUser();
    if (savedUser) setUser(savedUser);
  }, []);

  const handleLogout = () => {
    db.setCurrentUser(null);
    setUser(null);
    setCurrentPage('home');
  };

  const renderPage = () => {
    switch (currentPage) {
      case 'home': return <Home onNavigate={setCurrentPage} />;
      case 'login': return <Login onLogin={(u) => { setUser(u); setCurrentPage('dashboard'); }} onNavigate={setCurrentPage} />;
      case 'services': return <ServicesPage />;
      case 'request': return user ? <RequestService user={user} onComplete={() => setCurrentPage('dashboard')} /> : <Login onLogin={(u) => { setUser(u); setCurrentPage('request'); }} onNavigate={setCurrentPage} />;
      case 'dashboard': 
        if (!user) return <Login onLogin={(u) => { setUser(u); setCurrentPage('dashboard'); }} onNavigate={setCurrentPage} />;
        if (user.role === UserRole.ADMIN) return <AdminDashboard />;
        if (user.role === UserRole.TECHNICIAN) return <TechDashboard user={user} />;
        return <CustomerDashboard user={user} onNavigate={setCurrentPage} />;
      case 'careers': return <Careers />;
      case 'about': return <About />;
      case 'contact': return <Contact />;
      case 'pro': return <ProPlans />;
      default: return <Home onNavigate={setCurrentPage} />;
    }
  };

  return (
    <div className="min-h-screen flex flex-col bg-zinc-950 text-zinc-100">
      <Navbar 
        user={user} 
        onLogout={handleLogout} 
        onNavigate={setCurrentPage} 
        currentPage={currentPage}
      />
      <main className="flex-grow pt-20">
        {renderPage()}
      </main>
      <Footer onNavigate={setCurrentPage} />
    </div>
  );
};

export default App;

