- **public/**: Serves as the web root. `index.php` acts as a router.
- **src/**: Core backend logic. Models handle DB queries with PDO; Controllers process logic.
- **views/**: Templates with embedded PHP for dynamic content.
- **api/**: JSON-based endpoints for AJAX or future mobile app.
- **languages/**: JSON for translations; loaded via JS/PHP.

### Database Schema (SQL)
Run this in phpMyAdmin or MySQL CLI after setting up XAMPP. It creates the database and tables.

```sql
-- database/schema.sql
CREATE DATABASE autogo;
USE autogo;

-- Users table (supports roles: admin, technician, customer)
CREATE TABLE users (
    id INT AUTO_INCREMENT PRIMARY KEY,
    name VARCHAR(255) NOT NULL,
    email VARCHAR(255) UNIQUE NOT NULL,
    password VARCHAR(255) NOT NULL,  -- Hashed with bcrypt
    role ENUM('admin', 'technician', 'customer') DEFAULT 'customer',
    phone VARCHAR(20),
    location TEXT,  -- For customers/technicians
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

-- Roles table (for future expansion, e.g., permissions)
CREATE TABLE roles (
    id INT AUTO_INCREMENT PRIMARY KEY,
    name VARCHAR(50) UNIQUE NOT NULL
);
INSERT INTO roles (name) VALUES ('admin'), ('technician'), ('customer');

-- Service requests (core feature)
CREATE TABLE service_requests (
    id INT AUTO_INCREMENT PRIMARY KEY,
    customer_id INT NOT NULL,
    technician_id INT NULL,  -- Assigned later
    vehicle_id INT NULL,  -- Assigned vehicle
    problem_type VARCHAR(255),  -- e.g., 'Battery', 'Tire'
    location TEXT NOT NULL,  -- Highway/remote area
    status ENUM('pending', 'assigned', 'in_progress', 'completed') DEFAULT 'pending',
    priority BOOLEAN DEFAULT FALSE,  -- Highway priority
    notes TEXT,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
    FOREIGN KEY (customer_id) REFERENCES users(id),
    FOREIGN KEY (technician_id) REFERENCES users(id)
);

-- Vehicles (mobile garages)
CREATE TABLE vehicles (
    id INT AUTO_INCREMENT PRIMARY KEY,
    name VARCHAR(255) NOT NULL,
    type VARCHAR(100),  -- e.g., 'Truck', 'Van'
    status ENUM('available', 'in_use', 'maintenance') DEFAULT 'available',
    location TEXT
);

-- Technicians (subset of users, for assignments)
CREATE TABLE technicians (
    id INT AUTO_INCREMENT PRIMARY KEY,
    user_id INT UNIQUE NOT NULL,
    specialization VARCHAR(255),  -- e.g., 'Mechanical'
    FOREIGN KEY (user_id) REFERENCES users(id)
);

-- Subscriptions (AutoGo PRO)
CREATE TABLE subscriptions (
    id INT AUTO_INCREMENT PRIMARY KEY,
    user_id INT NOT NULL,
    plan VARCHAR(100),  -- e.g., 'Monthly'
    status ENUM('active', 'inactive') DEFAULT 'active',
    start_date DATE,
    end_date DATE,
    FOREIGN KEY (user_id) REFERENCES users(id)
);

-- Payments (for subscriptions, placeholder)
CREATE TABLE payments (
    id INT AUTO_INCREMENT PRIMARY KEY,
    user_id INT NOT NULL,
    amount DECIMAL(10,2),
    status ENUM('pending', 'completed') DEFAULT 'pending',
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    FOREIGN KEY (user_id) REFERENCES users(id)
);

-- Job applications (from Careers page)
CREATE TABLE job_applications (
    id INT AUTO_INCREMENT PRIMARY KEY,
    name VARCHAR(255),
    email VARCHAR(255),
    position VARCHAR(255),
    resume TEXT,  -- File path or content
    submitted_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

-- Reports (for admins)
CREATE TABLE reports (
    id INT AUTO_INCREMENT PRIMARY KEY,
    type VARCHAR(100),  -- e.g., 'Service Stats'
    data JSON,  -- Store stats as JSON
    generated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);
```

### Backend Code (PHP + MySQL)
Using pure PHP with MVC. Key files below. All use PDO for secure DB interactions.

#### src/config/database.php
```php
<?php
// Database connection using PDO
class Database {
    private static $instance = null;
    private $pdo;

    private function __construct() {
        $host = 'localhost';
        $db = 'autogo';
        $user = 'root';  // XAMPP default
        $pass = '';      // XAMPP default
        $this->pdo = new PDO("mysql:host=$host;dbname=$db", $user, $pass);
        $this->pdo->setAttribute(PDO::ATTR_ERRMODE, PDO::ERRMODE_EXCEPTION);
    }

    public static function getInstance() {
        if (self::$instance == null) {
            self::$instance = new Database();
        }
        return self::$instance->pdo;
    }
}
?>
```

#### src/models/User.php
```php
<?php
require_once __DIR__ . '/../config/database.php';

class User {
    private $pdo;

    public function __construct() {
        $this->pdo = Database::getInstance();
    }

    // Create user with hashed password
    public function create($name, $email, $password, $role = 'customer') {
        $hashed = password_hash($password, PASSWORD_BCRYPT);
        $stmt = $this->pdo->prepare("INSERT INTO users (name, email, password, role) VALUES (?, ?, ?, ?)");
        return $stmt->execute([$name, $email, $hashed, $role]);
    }

    // Authenticate user
    public function authenticate($email, $password) {
        $stmt = $this->pdo->prepare("SELECT * FROM users WHERE email = ?");
        $stmt->execute([$email]);
        $user = $stmt->fetch(PDO::FETCH_ASSOC);
        if ($user && password_verify($password, $user['password'])) {
            return $user;
        }
        return false;
    }

    // Get user by ID
    public function getById($id) {
        $stmt = $this->pdo->prepare("SELECT * FROM users WHERE id = ?");
        $stmt->execute([$id]);
        return $stmt->fetch(PDO::FETCH_ASSOC);
    }
}
?>
```

#### src/controllers/AuthController.php
```php
<?php
require_once __DIR__ . '/../models/User.php';
require_once __DIR__ . '/../utils/Auth.php';

class AuthController {
    private $userModel;

    public function __construct() {
        $this->userModel = new User();
    }

    // Handle login
    public function login($email, $password) {
        $user = $this->userModel->authenticate($email, $password);
        if ($user) {
            Auth::login($user['id'], $user['role']);
            return ['success' => true, 'role' => $user['role']];
        }
        return ['success' => false, 'message' => 'Invalid credentials'];
    }

    // Handle registration
    public function register($name, $email, $password, $role = 'customer') {
        if ($this->userModel->create($name, $email, $password, $role)) {
            return ['success' => true];
        }
        return ['success' => false, 'message' => 'Registration failed'];
    }
}
?>
```

#### public/api/auth.php (REST API Endpoint)
```php
<?php
header('Content-Type: application/json');
