// Route to views
if (Auth::isLoggedIn()) {
    $role = Auth::getRole();
    if ($role === 'admin') {
        include 'views/dashboards/admin.php';
    } elseif ($role === 'technician') {
        include 'views/dashboards/technician.php';
    } else {
        include 'views/dashboards/customer.php';
    }
} else {
    // Public pages
    $pages = ['home', 'problem_solution', 'services', 'how_it_works', 'coverage', 'pro', 'careers', 'about', 'contact', 'login', 'register'];
    if (in_array($page, $pages)) {
        include "views/public/$page.php";
    } else {
        include 'views/public/home.php';  // Default
    }
}
?>
```

### Frontend Code (HTML, CSS, JS)
Using Bootstrap 5, dark theme, and Font Awesome. Includes RTL support via CSS classes.

#### public/assets/css/style.css
```css
