  onNavigate: (page: string) => void;
  currentPage: string;
  lang: Language;
  setLang: (lang: Language) => void;
}

const Navbar: React.FC<NavbarProps> = ({ user, onLogout, onNavigate, currentPage, lang, setLang }) => {
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [isLangOpen, setIsLangOpen] = useState(false);
  const langRef = useRef<HTMLDivElement>(null);
  const t = translations[lang].nav;

  const languages: { id: Language; label: string; flag: string }[] = [
    { id: 'en', label: 'English', flag: '🇺🇸' },
    { id: 'ar', label: 'العربية', flag: '🇪🇬' },
    { id: 'fr', label: 'Français', flag: '🇫🇷' },
    { id: 'de', label: 'Deutsch', flag: '🇩🇪' },
    { id: 'es', label: 'Español', flag: '🇪🇸' },
  ];

  const currentLangObj = languages.find(l => l.id === lang) || languages[0];

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (langRef.current && !langRef.current.contains(event.target as Node)) {
        setIsLangOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const navLinks = [
    { id: 'home', label: t.home },
    { id: 'services', label: t.services },
    { id: 'coverage', label: t.coverage },
    { id: 'pro', label: t.pro },
    { id: 'about', label: t.about },
    { id: 'careers', label: t.careers },
  ];

  return (
    <nav className="fixed w-full z-[100] bg-zinc-950/80 backdrop-blur-md border-b border-zinc-800">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex items-center justify-between h-20">
          <div className="flex items-center">
            <button onClick={() => onNavigate('home')} className="flex items-center gap-2 group">
              <div className="w-10 h-10 bg-blue-600 rounded-lg flex items-center justify-center transform group-hover:rotate-12 transition-transform">
                <i className="fa-solid fa-car-side text-white"></i>
              </div>
              <span className="font-brand text-2xl font-bold tracking-tighter text-white">
                Auto<span className="text-blue-500">Go</span>
              </span>
            </button>
          </div>

          <div className="hidden md:block">
            <div className={`flex items-baseline ${lang === 'ar' ? 'space-x-reverse space-x-4' : 'space-x-4'}`}>
              {navLinks.map(link => (
                <button
                  key={link.id}
                  onClick={() => onNavigate(link.id)}
                  className={`px-3 py-2 rounded-md text-sm font-medium transition-colors ${
                    currentPage === link.id ? 'text-blue-500' : 'text-zinc-400 hover:text-white'
                  }`}
                >
                  {link.label}
                </button>
              ))}
            </div>
          </div>

          <div className="hidden md:flex items-center gap-6">
            {/* Language Dropdown */}
            <div className="relative" ref={langRef}>
              <button 
                onClick={() => setIsLangOpen(!isLangOpen)}
                className="flex items-center gap-2 bg-zinc-900 border border-zinc-800 hover:border-zinc-700 px-3 py-1.5 rounded-lg transition-all text-sm font-semibold"
              >
                <span>{currentLangObj.flag}</span>
                <span className="text-zinc-300">{currentLangObj.id.toUpperCase()}</span>
                <i className={`fa-solid fa-chevron-down text-[10px] text-zinc-500 transition-transform ${isLangOpen ? 'rotate-180' : ''}`}></i>
              </button>

              {isLangOpen && (
                <div className={`absolute top-full mt-2 w-40 bg-zinc-900 border border-zinc-800 rounded-xl shadow-2xl py-2 animate-in fade-in slide-in-from-top-2 ${lang === 'ar' ? 'left-0' : 'right-0'}`}>
                  {languages.map(l => (
                    <button
                      key={l.id}
                      onClick={() => { setLang(l.id); setIsLangOpen(false); }}
                      className={`w-full flex items-center justify-between px-4 py-2.5 text-sm hover:bg-zinc-800 transition-colors ${lang === l.id ? 'text-blue-500 font-bold bg-blue-500/5' : 'text-zinc-400'}`}
                    >
                      <span>{l.label}</span>
                      <span className="opacity-50">{l.flag}</span>
                    </button>
                  ))}
                </div>
              )}
            </div>

            {user ? (
              <div className="flex items-center gap-4">
                <button 
                  onClick={() => onNavigate('dashboard')}
                  className={`text-sm font-medium transition-colors ${currentPage === 'dashboard' ? 'text-blue-500' : 'text-zinc-400 hover:text-white'}`}
                >
                  {t.dashboard}
                </button>
                <button 
                  onClick={() => onNavigate('profile')}
                  className="flex items-center gap-2 group"
                >
                  <div className="w-8 h-8 rounded-full bg-zinc-800 border border-zinc-700 overflow-hidden">
                    {user.avatar ? (
                      <img src={user.avatar} alt={user.name} className="w-full h-full object-cover" />
                    ) : (
                      <div className="w-full h-full flex items-center justify-center text-xs font-bold text-zinc-500">
                        {user.name.charAt(0).toUpperCase()}
                      </div>
                    )}
                  </div>
                </button>
                <button 
                  onClick={onLogout}
                  className="text-zinc-500 hover:text-red-500 transition-colors text-xs"
