      </div>

      {/* Mobile Menu */}
      {isMenuOpen && (
        <div className="md:hidden bg-zinc-900 border-b border-zinc-800 animate-in slide-in-from-top">
          <div className="flex gap-2 p-4 border-b border-zinc-800">
            {languages.map(l => (
              <button
                key={l.id}
                onClick={() => { setLang(l.id); setIsMenuOpen(false); }}
                className={`flex-1 py-2 text-center rounded-lg border ${lang === l.id ? 'bg-blue-600 border-blue-500 text-white' : 'bg-zinc-950 border-zinc-800 text-zinc-500'}`}
              >
                {l.flag}
              </button>
            ))}
          </div>

          <div className="px-2 pt-2 pb-3 space-y-1 sm:px-3">
            {navLinks.map(link => (
              <button
                key={link.id}
                onClick={() => { onNavigate(link.id); setIsMenuOpen(false); }}
