          </div>
        </div>
      )}
    </nav>
  );
};

export default Navbar;

import React, { useState, useRef } from 'react';
import { User } from '../types';
import { db } from '../services/db';
import { Language } from '../translations';

interface ProfileProps {
  user: User;
  onUpdate: (user: User) => void;
  lang: Language;
}

const Profile: React.FC<ProfileProps> = ({ user, onUpdate, lang }) => {
  const [formData, setFormData] = useState({
    name: user.name,
    phone: user.phone || '',
    address: user.address || '',
    avatar: user.avatar || ''
  });
  const [isSaving, setIsSaving] = useState(false);
  const [message, setMessage] = useState<{ type: 'success' | 'error', text: string } | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setFormData({ ...formData, avatar: reader.result as string });
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setIsSaving(true);
    setMessage(null);

    const updated = db.updateUser(user.id, formData);
    if (updated) {
      onUpdate(updated);
      setMessage({ type: 'success', text: lang === 'ar' ? 'تم تحديث البيانات بنجاح!' : 'Profile updated successfully!' });
    } else {
      setMessage({ type: 'error', text: lang === 'ar' ? 'فشل التحديث.' : 'Update failed.' });
    }

    setTimeout(() => {
      setIsSaving(false);
      setMessage(null);
    }, 3000);
  };

  return (
    <div className="max-w-4xl mx-auto px-4 py-12">
      <div className="bg-zinc-900 border border-zinc-800 rounded-[2.5rem] overflow-hidden shadow-2xl">
        <div className="h-32 bg-gradient-to-r from-blue-600 to-indigo-700"></div>

        <div className={`px-8 md:px-12 pb-12 -mt-16 ${lang === 'ar' ? 'text-right' : ''}`}>
          <div className={`flex flex-col md:flex-row items-end gap-6 mb-12 ${lang === 'ar' ? 'md:flex-row-reverse' : ''}`}>
            <div className="relative group">
              <div className="w-32 h-32 rounded-3xl bg-zinc-800 border-4 border-zinc-900 overflow-hidden shadow-xl">
                {formData.avatar ? (
                  <img src={formData.avatar} alt="Avatar" className="w-full h-full object-cover" />
                ) : (
                  <div className="w-full h-full flex items-center justify-center text-4xl font-bold text-zinc-700">
                    {user.name.charAt(0).toUpperCase()}
                  </div>
                )}
              </div>
              <button 
                onClick={() => fileInputRef.current?.click()}
                className="absolute bottom-2 right-2 w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center text-white shadow-lg hover:bg-blue-700 transition-all"
              >
                <i className="fa-solid fa-camera"></i>
              </button>
              <input 
                type="file" 
                ref={fileInputRef} 
                onChange={handleFileChange} 
                className="hidden" 
                accept="image/*" 
              />
            </div>

            <div className="flex-grow mb-2">
              <h1 className="text-3xl font-bold font-brand">{user.name}</h1>
              <p className="text-zinc-500">{user.email}</p>
              <div className="flex gap-2 mt-2">
                <span className="px-3 py-1 bg-zinc-800 rounded-lg text-[10px] font-bold text-zinc-400 uppercase tracking-widest border border-zinc-700">
                  {user.role}
                </span>
                {user.isPro && (
                  <span className="px-3 py-1 bg-amber-500/10 rounded-lg text-[10px] font-bold text-amber-500 uppercase tracking-widest border border-amber-500/20">
                    PRO MEMBER
                  </span>
                )}
              </div>
            </div>
          </div>

          <form onSubmit={handleSubmit} className="grid md:grid-cols-2 gap-8">
            {message && (
              <div className={`md:col-span-2 p-4 rounded-xl text-sm flex items-center gap-3 animate-in slide-in-from-top-2 ${
                message.type === 'success' ? 'bg-emerald-500/10 text-emerald-500 border border-emerald-500/20' : 'bg-red-500/10 text-red-500 border border-red-500/20'
              }`}>
                <i className={`fa-solid ${message.type === 'success' ? 'fa-circle-check' : 'fa-circle-exclamation'}`}></i>
                {message.text}
              </div>
            )}

            <div className="space-y-6">
              <div>
                <label className="block text-sm font-medium text-zinc-500 mb-2">{lang === 'ar' ? 'الاسم الكامل' : 'Full Name'}</label>
                <input 
                  type="text" 
                  className={`w-full bg-zinc-950 border border-zinc-800 rounded-xl px-4 py-3 focus:ring-2 focus:ring-blue-500 outline-none ${lang === 'ar' ? 'text-right' : ''}`}
                  value={formData.name}
                  onChange={e => setFormData({ ...formData, name: e.target.value })}
                  required
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-zinc-500 mb-2">{lang === 'ar' ? 'رقم الهاتف' : 'Phone Number'}</label>
                <input 
                  type="tel" 
                  placeholder="01xxxxxxxxx"
                  className={`w-full bg-zinc-950 border border-zinc-800 rounded-xl px-4 py-3 focus:ring-2 focus:ring-blue-500 outline-none ${lang === 'ar' ? 'text-right' : ''}`}
                  value={formData.phone}
                  onChange={e => setFormData({ ...formData, phone: e.target.value })}
                />
              </div>
            </div>

            <div className="space-y-6">
              <div>
                <label className="block text-sm font-medium text-zinc-500 mb-2">{lang === 'ar' ? 'العنوان المفضل' : 'Primary Address'}</label>
                <textarea 
                  rows={4}
                  placeholder={lang === 'ar' ? 'مثال: المعادي، القاهرة' : 'e.g. Maadi, Cairo'}
                  className={`w-full bg-zinc-950 border border-zinc-800 rounded-xl px-4 py-3 focus:ring-2 focus:ring-blue-500 outline-none resize-none ${lang === 'ar' ? 'text-right' : ''}`}
                  value={formData.address}
                  onChange={e => setFormData({ ...formData, address: e.target.value })}
                ></textarea>
              </div>

              <button 
                type="submit" 
                disabled={isSaving}
                className="w-full bg-blue-600 hover:bg-blue-700 disabled:opacity-50 text-white font-bold py-4 rounded-xl transition-all shadow-xl shadow-blue-600/20"
              >
                {isSaving ? (
                  <><i className="fa-solid fa-spinner fa-spin mr-2"></i> {lang === 'ar' ? 'جاري الحفظ...' : 'Saving...'}</>
                ) : (
                  lang === 'ar' ? 'حفظ التعديلات' : 'Save Profile'
                )}
              </button>
            </div>
          </form>
        </div>
      </div>
    </div>
  );
};

export default Profile;

