                >
                  <option value={UserRole.CUSTOMER}>Driver (Owner)</option>
                  <option value={UserRole.TECHNICIAN}>Expert Tech</option>
                </select>
              </div>
            </div>

            <div>
              <label className="block text-sm font-bold text-zinc-500 mb-2 ml-1">Email</label>
              <input 
                type="email" 
                required
                className="w-full bg-zinc-950 border border-zinc-800 rounded-2xl px-5 py-4 focus:ring-2 focus:ring-blue-500 outline-none text-white transition-all shadow-inner"
                placeholder="ali@auto.go"
