import React, { useState, useRef, useEffect } from 'react';
import { User, UserRole, RequestStatus } from '../types';
import { db } from '../services/db';
import { translations, Language } from '../translations';

interface NavbarProps {
  user: User | null;
  onLogout: () => void;
  onNavigate: (page: string) => void;
  currentPage: string;
  lang: Language;
  setLang: (lang: Language) => void;
}

const Navbar: React.FC<NavbarProps> = ({ user, onLogout, onNavigate, currentPage, lang, setLang }) => {
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [isLangOpen, setIsLangOpen] = useState(false);
  const [hasActiveTracking, setHasActiveTracking] = useState(false);
  const langRef = useRef<HTMLDivElement>(null);
  const t = translations[lang].nav;

  useEffect(() => {
    if (user && user.role === UserRole.CUSTOMER) {
      const checkTracking = () => {
        const requests = db.getRequests();
        const active = requests.find(r => 
          r.customerId === user.id && 
          (r.status === RequestStatus.ASSIGNED || r.status === RequestStatus.IN_PROGRESS)
        );
        setHasActiveTracking(!!active);
      };
      checkTracking();
      const interval = setInterval(checkTracking, 5000);
      return () => clearInterval(interval);
    }
  }, [user]);

  const languages: { id: Language; label: string; flag: string }[] = [
    { id: 'en', label: 'English', flag: '🇺🇸' },
    { id: 'ar', label: 'العربية', flag: '🇪🇬' },
  ];

  const currentLangObj = languages.find(l => l.id === lang) || languages[0];

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (langRef.current && !langRef.current.contains(event.target as Node)) {
        setIsLangOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  return (
    <nav className="fixed w-full z-[100] bg-zinc-950/80 backdrop-blur-xl border-b border-zinc-900">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex items-center justify-between h-20">
          <div className="flex items-center">
            <button onClick={() => onNavigate('home')} className="flex items-center gap-2 group">
              <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center transform group-hover:rotate-12 transition-transform shadow-lg shadow-blue-600/20">
                <i className="fa-solid fa-bolt-lightning text-white"></i>
              </div>
              <span className="font-brand text-2xl font-black tracking-tighter text-white">
                Auto<span className="text-blue-500">Go</span>
              </span>
            </button>
          </div>

          <div className="hidden md:flex items-center space-x-8">
            <button onClick={() => onNavigate('home')} className={`text-sm font-bold transition-colors ${currentPage === 'home' ? 'text-blue-500' : 'text-zinc-500 hover:text-white'}`}>{t.home}</button>
            <button onClick={() => onNavigate('services')} className={`text-sm font-bold transition-colors ${currentPage === 'services' ? 'text-blue-500' : 'text-zinc-500 hover:text-white'}`}>{t.services}</button>
            <button onClick={() => onNavigate('pro')} className={`text-sm font-bold transition-colors ${currentPage === 'pro' ? 'text-blue-500' : 'text-zinc-500 hover:text-white'}`}>{t.pro}</button>
            <button onClick={() => onNavigate('careers')} className={`text-sm font-bold transition-colors ${currentPage === 'careers' ? 'text-blue-500' : 'text-zinc-500 hover:text-white'}`}>{t.careers}</button>
          </div>

          <div className="flex items-center gap-6">
             {hasActiveTracking && (
               <button 
                 onClick={() => onNavigate('dashboard')}
                 className="hidden md:flex items-center gap-2 bg-blue-600/10 border border-blue-500/20 px-4 py-2 rounded-full animate-pulse"
               >
                 <span className="flex h-2 w-2">
                   <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-blue-400 opacity-75"></span>
                   <span className="relative inline-flex rounded-full h-2 w-2 bg-blue-500"></span>
                 </span>
                 <span className="text-[10px] font-black uppercase tracking-widest text-blue-500">Live Tracking</span>
               </button>
             )}

            <div className="relative" ref={langRef}>
              <button onClick={() => setIsLangOpen(!isLangOpen)} className="flex items-center gap-2 bg-zinc-900 border border-zinc-800 px-3 py-1.5 rounded-lg text-sm font-bold">
                <span>{currentLangObj.flag}</span>
                <i className="fa-solid fa-chevron-down text-[10px] text-zinc-600"></i>
              </button>
              {isLangOpen && (
                <div className="absolute top-full mt-2 w-32 bg-zinc-900 border border-zinc-800 rounded-xl shadow-2xl py-2">
                  {languages.map(l => (
                    <button key={l.id} onClick={() => { setLang(l.id); setIsLangOpen(false); }} className="w-full text-left px-4 py-2 text-xs hover:bg-zinc-800 text-zinc-400 hover:text-white font-bold">
                      {l.label}
                    </button>
                  ))}
                </div>
              )}
            </div>

            {user ? (
              <div className="flex items-center gap-4">
                <button onClick={() => onNavigate('dashboard')} className="w-10 h-10 rounded-full border-2 border-zinc-800 overflow-hidden hover:border-blue-500 transition-colors">
                  <img src={user.avatar || `https://ui-avatars.com/api/?name=${user.name}&background=18181b&color=3b82f6`} alt="profile" className="w-full h-full object-cover" />
                </button>
                <button onClick={onLogout} className="text-zinc-600 hover:text-red-500 transition-colors">
                  <i className="fa-solid fa-power-off"></i>
                </button>
              </div>
            ) : (
              <button onClick={() => onNavigate('login')} className="bg-blue-600 hover:bg-blue-700 text-white px-6 py-2.5 rounded-xl text-sm font-black shadow-lg shadow-blue-600/20">
                {t.signIn}
              </button>
            )}
          </div>
        </div>
      </div>
    </nav>
  );
};

export default Navbar;

