  init: () => {
    if (!localStorage.getItem(KEYS.USERS)) {
      localStorage.setItem(KEYS.USERS, JSON.stringify(DEFAULT_USERS));
    }
    if (!localStorage.getItem(KEYS.REQUESTS)) {
      localStorage.setItem(KEYS.REQUESTS, JSON.stringify([]));
    }
    if (!localStorage.getItem(KEYS.APPLICATIONS)) {
      localStorage.setItem(KEYS.APPLICATIONS, JSON.stringify([]));
    }
  },

  getUsers: (): User[] => JSON.parse(localStorage.getItem(KEYS.USERS) || '[]'),

  registerUser: (userData: Omit<User, 'id'>) => {
    const users = db.getUsers();
    const existingUser = users.find(u => u.email.toLowerCase() === userData.email.toLowerCase());

    if (existingUser) {
      return existingUser;
    }

    const newUser: User = {
      ...userData,
      id: Math.random().toString(36).substr(2, 9),
    };

    users.push(newUser);
    localStorage.setItem(KEYS.USERS, JSON.stringify(users));
    return newUser;
  },

  updateUser: (id: string, updates: Partial<User>) => {
    const users = db.getUsers();
    const index = users.findIndex(u => u.id === id);
    if (index !== -1) {
      const updatedUser = { ...users[index], ...updates };
      users[index] = updatedUser;
      localStorage.setItem(KEYS.USERS, JSON.stringify(users));

      const current = db.getCurrentUser();
      if (current && current.id === id) {
        db.setCurrentUser(updatedUser);
      }
      return updatedUser;
    }
    return null;
  },

  getRequests: (): ServiceRequest[] => JSON.parse(localStorage.getItem(KEYS.REQUESTS) || '[]'),

  addRequest: (request: Omit<ServiceRequest, 'id' | 'status' | 'createdAt'>) => {
    const requests = db.getRequests();
    const newRequest: ServiceRequest = {
      ...request,
      id: Math.random().toString(36).substr(2, 9),
      status: RequestStatus.PENDING,
      createdAt: new Date().toISOString()
    };
    requests.push(newRequest);
    localStorage.setItem(KEYS.REQUESTS, JSON.stringify(requests));
    return newRequest;
  },

  updateRequest: (id: string, updates: Partial<ServiceRequest>) => {
    const requests = db.getRequests();
    const index = requests.findIndex(r => r.id === id);
    if (index !== -1) {
      requests[index] = { ...requests[index], ...updates };
      localStorage.setItem(KEYS.REQUESTS, JSON.stringify(requests));
    }
  },

  getApplications: (): JobApplication[] => JSON.parse(localStorage.getItem(KEYS.APPLICATIONS) || '[]'),

  addApplication: (application: Omit<JobApplication, 'id' | 'status'>) => {
    const applications = db.getApplications();
    const newApp: JobApplication = {
      ...application,
      id: Math.random().toString(36).substr(2, 9),
      status: 'PENDING'
    };
    applications.push(newApp);
    localStorage.setItem(KEYS.APPLICATIONS, JSON.stringify(applications));
    return newApp;
  },

  getCurrentUser: (): User | null => {
    const user = localStorage.getItem(KEYS.CURRENT_USER);
    return user ? JSON.parse(user) : null;
  },

  setCurrentUser: (user: User | null) => {
    if (user) localStorage.setItem(KEYS.CURRENT_USER, JSON.stringify(user));
    else localStorage.removeItem(KEYS.CURRENT_USER);
  }
};

import React, { useState } from 'react';
import { db } from '../services/db';
import { notificationService } from '../services/notification';
import { User, UserRole } from '../types';

interface SignupProps {
  onLogin: (user: User) => void;
  onNavigate: (page: string) => void;
}

const Signup: React.FC<SignupProps> = ({ onLogin, onNavigate }) => {
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    password: '',
    role: UserRole.CUSTOMER
  });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    // Ensure email is trimmed
    const cleanEmail = formData.email.trim();

    // Perceivable delay for reliability feel
    await new Promise(resolve => setTimeout(resolve, 1500));

    try {
      const user = db.registerUser({
        name: formData.name,
        email: cleanEmail,
        role: formData.role
      });

      notificationService.notifyAdminOnRegistration(user).catch(() => {});
      db.setCurrentUser(user);
      onLogin(user);
    } catch (err: any) {
      setError('System unavailable. Please try again.');
      setLoading(false);
    }
  };

  return (
    <div className="min-h-[85vh] flex items-center justify-center px-4 py-12 animate-in fade-in zoom-in duration-500">
      <div className="bg-zinc-900 p-8 md:p-12 rounded-[3rem] border border-zinc-800 w-full max-w-lg shadow-2xl relative overflow-hidden">
        <div className="absolute -top-24 -right-24 w-64 h-64 bg-blue-600/10 rounded-full blur-[80px]"></div>

        <div className="relative z-10">
          <div className="text-center mb-12">
            <h2 className="text-5xl font-black font-brand mb-4 text-white tracking-tighter">
              Auto<span className="text-blue-500">Go</span>
            </h2>
            <p className="text-zinc-500 font-medium">Join 12,000+ drivers who fixed it on the spot</p>
          </div>

          <form onSubmit={handleSubmit} className="space-y-6">
            {error && (
              <div className="bg-red-500/10 border border-red-500/20 text-red-500 p-4 rounded-2xl text-sm font-bold flex items-center gap-3">
                <i className="fa-solid fa-circle-exclamation"></i>
                {error}
              </div>
            )}

            <div className="grid md:grid-cols-2 gap-5">
              <div>
                <label className="block text-xs font-black uppercase tracking-widest text-zinc-600 mb-3 ml-1">Full Name</label>
                <input 
                  type="text" 
                  required
                  className="w-full bg-zinc-950 border border-zinc-800 rounded-2xl px-5 py-4 focus:ring-2 focus:ring-blue-500 outline-none text-white transition-all shadow-inner"
                  placeholder="Ali Ahmed"
                  value={formData.name}
                  onChange={e => setFormData({...formData, name: e.target.value})}
                />
              </div>
              <div>
                <label className="block text-xs font-black uppercase tracking-widest text-zinc-600 mb-3 ml-1">Account Type</label>
                <select 
                  className="w-full bg-zinc-950 border border-zinc-800 rounded-2xl px-5 py-4 focus:ring-2 focus:ring-blue-500 outline-none appearance-none text-white shadow-inner"
                  value={formData.role}
                  onChange={e => setFormData({...formData, role: e.target.value as UserRole})}
                >
                  <option value={UserRole.CUSTOMER}>Driver (Owner)</option>
                  <option value={UserRole.TECHNICIAN}>Expert Tech</option>
                </select>
              </div>
            </div>

            <div>
              <label className="block text-xs font-black uppercase tracking-widest text-zinc-600 mb-3 ml-1">Email Address</label>
              <input 
                type="email" 
                required
                className="w-full bg-zinc-950 border border-zinc-800 rounded-2xl px-5 py-4 focus:ring-2 focus:ring-blue-500 outline-none text-white transition-all shadow-inner"
                placeholder="ali@auto.go"
                value={formData.email}
                onChange={e => setFormData({...formData, email: e.target.value})}
              />
            </div>

            <div>
              <label className="block text-xs font-black uppercase tracking-widest text-zinc-600 mb-3 ml-1">Secure Password</label>
              <input 
                type="password" 
                required
                className="w-full bg-zinc-950 border border-zinc-800 rounded-2xl px-5 py-4 focus:ring-2 focus:ring-blue-500 outline-none text-white transition-all shadow-inner"
                placeholder="••••••••"
                value={formData.password}
                onChange={e => setFormData({...formData, password: e.target.value})}
              />
            </div>

            <button 
              type="submit"
              disabled={loading}
              className="w-full bg-blue-600 hover:bg-blue-700 disabled:opacity-50 text-white font-black py-5 rounded-2xl transition-all shadow-2xl shadow-blue-600/30 text-xl hover:-translate-y-1 active:scale-95"
            >
              {loading ? (
                <div className="flex items-center justify-center gap-3">
                  <div className="w-6 h-6 border-4 border-white/20 border-t-white rounded-full animate-spin"></div>
                  <span>Verifying...</span>
                </div>
              ) : (
                'Create Account'
              )}
            </button>
          </form>

          <div className="mt-10 text-center">
            <p className="text-zinc-500 font-medium">
              Already a member? <button onClick={() => onNavigate('login')} className="text-blue-500 font-bold hover:underline">Sign In</button>
            </p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Signup;

