                <div className="absolute top-full right-0 mt-2 w-32 bg-zinc-900 border border-zinc-800 rounded-xl shadow-2xl py-2 animate-in slide-in-from-top-2">
                  {languages.map(l => (
                    <button key={l.id} onClick={() => { setLang(l.id); setIsLangOpen(false); }} className="w-full text-left px-4 py-2 text-xs hover:bg-zinc-800 text-zinc-400 hover:text-white font-bold transition-colors">
                      {l.label}
