import React, { useState, useEffect } from 'react';
import { User, UserRole } from './types';
import { db } from './services/db';
import Navbar from './components/Navbar';
import Home from './pages/Home';
import Login from './pages/Login';
import Signup from './pages/Signup';
import RequestService from './pages/RequestService';
import CustomerDashboard from './pages/CustomerDashboard';
import AdminDashboard from './pages/AdminDashboard';
import TechDashboard from './pages/TechDashboard';
import Careers from './pages/Careers';
import About from './pages/About';
import Contact from './pages/Contact';
import ServicesPage from './pages/ServicesPage';
import ProPlans from './pages/ProPlans';
import Coverage from './pages/Coverage';
import PrivacyPolicy from './pages/PrivacyPolicy';
import TermsOfService from './pages/TermsOfService';
import FleetSales from './pages/FleetSales';
import Payment from './pages/Payment';
import Profile from './pages/Profile';
import Footer from './components/Footer';
import LoadingScreen from './components/LoadingScreen';
import { translations, Language } from './translations';

const App: React.FC = () => {
  const [currentPage, setCurrentPage] = useState<string>('home');
  const [selectedPlan, setSelectedPlan] = useState<any>(null);
  const [user, setUser] = useState<User | null>(null);
  const [lang, setLang] = useState<Language>('en');
  const [isInitialLoading, setIsInitialLoading] = useState(true);

  useEffect(() => {
    db.init();
    const savedUser = db.getCurrentUser();
    if (savedUser) setUser(savedUser);

    const timer = setTimeout(() => {
      setIsInitialLoading(false);
    }, 1200); // Shorter duration for snappier feel

    return () => clearTimeout(timer);
  }, []);

  useEffect(() => {
    document.documentElement.dir = lang === 'ar' ? 'rtl' : 'ltr';
    document.documentElement.lang = lang;
  }, [lang]);

  useEffect(() => {
    window.scrollTo({ top: 0, behavior: 'smooth' });
  }, [currentPage]);

  const handleLogout = () => {
    db.setCurrentUser(null);
    setUser(null);
    setCurrentPage('home');
  };

  const handleUpdateUser = (updatedUser: User) => {
    setUser(updatedUser);
  };

  const navigateToPayment = (plan: any) => {
    if (!user) {
      setCurrentPage('login');
      return;
    }
    setSelectedPlan(plan);
    setCurrentPage('payment');
  };

  const renderPage = () => {
    switch (currentPage) {
      case 'home': return <Home onNavigate={setCurrentPage} lang={lang} />;
      case 'login': return <Login onLogin={(u) => { setUser(u); setCurrentPage('dashboard'); }} onNavigate={setCurrentPage} />;
      case 'signup': return <Signup onLogin={(u) => { setUser(u); setCurrentPage('dashboard'); }} onNavigate={setCurrentPage} />;
      case 'services': return <ServicesPage onNavigate={setCurrentPage} lang={lang} />;
      case 'coverage': return <Coverage />;
      case 'request': return user ? <RequestService user={user} onComplete={() => setCurrentPage('dashboard')} lang={lang} /> : <Login onLogin={(u) => { setUser(u); setCurrentPage('request'); }} onNavigate={setCurrentPage} />;
      case 'dashboard': 
        if (!user) return <Login onLogin={(u) => { setUser(u); setCurrentPage('dashboard'); }} onNavigate={setCurrentPage} />;
        if (user.role === UserRole.ADMIN) return <AdminDashboard />;
        if (user.role === UserRole.TECHNICIAN) return <TechDashboard user={user} />;
        return <CustomerDashboard user={user} onNavigate={setCurrentPage} />;
      case 'profile': return user ? <Profile user={user} onUpdate={handleUpdateUser} lang={lang} /> : <Login onLogin={(u) => { setUser(u); setCurrentPage('profile'); }} onNavigate={setCurrentPage} />;
      case 'careers': return <Careers />;
      case 'about': return <About />;
      case 'contact': return <Contact lang={lang} />;
      case 'pro': return <ProPlans onSubscribe={navigateToPayment} />;
      case 'payment': return <Payment plan={selectedPlan} user={user!} lang={lang} onComplete={() => setCurrentPage('dashboard')} />;
      case 'privacy': return <PrivacyPolicy />;
      case 'terms': return <TermsOfService />;
      case 'fleet': return <FleetSales onNavigate={setCurrentPage} />;
      default: return <Home onNavigate={setCurrentPage} lang={lang} />;
    }
  };

  if (isInitialLoading) {
    return <LoadingScreen />;
  }

  return (
    <div className={`min-h-screen flex flex-col bg-zinc-950 text-zinc-100 animate-in fade-in duration-700 ${lang === 'ar' ? 'font-arabic' : ''}`}>
      <Navbar 
        user={user} 
        onLogout={handleLogout} 
        onNavigate={onNavigate => setCurrentPage(onNavigate)} 
        currentPage={currentPage}
        lang={lang}
        setLang={setLang}
      />
      <main className="flex-grow pt-24 md:pt-32">
        {renderPage()}
      </main>
      <Footer onNavigate={setCurrentPage} lang={lang} />
    </div>
  );
};

export default App;

import { User, UserRole, ServiceRequest, RequestStatus, JobApplication } from '../types';

const KEYS = {
  USERS: 'autogo_users',
  REQUESTS: 'autogo_requests',
  APPLICATIONS: 'autogo_applications',
  CURRENT_USER: 'autogo_current_user'
};

const DEFAULT_USERS: User[] = [
  { id: '1', name: 'Admin User', email: 'admin@autogo.com', role: UserRole.ADMIN },
  { id: '2', name: 'John Tech', email: 'tech@autogo.com', role: UserRole.TECHNICIAN },
  { id: '3', name: 'Mohamed Ahmed', email: 'mohamed@autogo.com', role: UserRole.CUSTOMER, isPro: true }
];

export const db = {
  init: () => {
    if (!localStorage.getItem(KEYS.USERS)) {
      localStorage.setItem(KEYS.USERS, JSON.stringify(DEFAULT_USERS));
    }
    if (!localStorage.getItem(KEYS.REQUESTS)) {
      localStorage.setItem(KEYS.REQUESTS, JSON.stringify([]));
    }
    if (!localStorage.getItem(KEYS.APPLICATIONS)) {
      localStorage.setItem(KEYS.APPLICATIONS, JSON.stringify([]));
    }
  },

  getUsers: (): User[] => {
    try {
      return JSON.parse(localStorage.getItem(KEYS.USERS) || '[]');
    } catch {
      return DEFAULT_USERS;
    }
  },

  registerUser: (userData: Omit<User, 'id'>) => {
    const users = db.getUsers();
    const existingUser = users.find(u => u.email.toLowerCase() === userData.email.toLowerCase());

    if (existingUser) {
      // If user exists, update their role if it's different and return them (like a login)
      return existingUser;
    }

    const newUser: User = {
      ...userData,
      id: Math.random().toString(36).substr(2, 9),
    };

    users.push(newUser);
    localStorage.setItem(KEYS.USERS, JSON.stringify(users));
    return newUser;
  },

  updateUser: (id: string, updates: Partial<User>) => {
    const users = db.getUsers();
    const index = users.findIndex(u => u.id === id);
    if (index !== -1) {
      const updatedUser = { ...users[index], ...updates };
      users[index] = updatedUser;
      localStorage.setItem(KEYS.USERS, JSON.stringify(users));

      const current = db.getCurrentUser();
      if (current && current.id === id) {
        db.setCurrentUser(updatedUser);
      }
      return updatedUser;
    }
    return null;
  },

  getRequests: (): ServiceRequest[] => {
    try {
      return JSON.parse(localStorage.getItem(KEYS.REQUESTS) || '[]');
    } catch {
      return [];
    }
  },

  addRequest: (request: Omit<ServiceRequest, 'id' | 'status' | 'createdAt'>) => {
    const requests = db.getRequests();
    const newRequest: ServiceRequest = {
      ...request,
      id: 'atg-' + Math.random().toString(36).substr(2, 5),
      status: RequestStatus.PENDING,
      createdAt: new Date().toISOString()
    };
    requests.push(newRequest);
    localStorage.setItem(KEYS.REQUESTS, JSON.stringify(requests));
    return newRequest;
  },

  updateRequest: (id: string, updates: Partial<ServiceRequest>) => {
    const requests = db.getRequests();
    const index = requests.findIndex(r => r.id === id);
    if (index !== -1) {
      requests[index] = { ...requests[index], ...updates };
      localStorage.setItem(KEYS.REQUESTS, JSON.stringify(requests));
    }
  },

  // Fix: Added addApplication to handle job applications from Careers.tsx
  addApplication: (application: Omit<JobApplication, 'id' | 'status'>) => {
    let applications: JobApplication[] = [];
    try {
      applications = JSON.parse(localStorage.getItem(KEYS.APPLICATIONS) || '[]');
    } catch {
      applications = [];
    }

    const newApplication: JobApplication = {
      ...application,
      id: 'app-' + Math.random().toString(36).substr(2, 5),
      status: 'PENDING'
    };

    applications.push(newApplication);
    localStorage.setItem(KEYS.APPLICATIONS, JSON.stringify(applications));
    return newApplication;
  },

  getCurrentUser: (): User | null => {
    const user = localStorage.getItem(KEYS.CURRENT_USER);
    return user ? JSON.parse(user) : null;
  },

  setCurrentUser: (user: User | null) => {
    if (user) localStorage.setItem(KEYS.CURRENT_USER, JSON.stringify(user));
    else localStorage.removeItem(KEYS.CURRENT_USER);
  }
};

import { GoogleGenAI } from "@google/genai";

// Always use const ai = new GoogleGenAI({apiKey: process.env.API_KEY});
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// Fix: Using gemini-3-pro-preview for diagnostic tasks as it involves complex reasoning
export const diagnoseProblem = async (problemType: string, description: string) => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: `User reports a ${problemType} issue with their car. Description: ${description}. 
                 Provide a short, professional, encouraging 'Smart Diagnosis' for a mobile mechanic dispatch. 
                 Mention potential causes and what the technician will likely check. Keep it under 100 words.`,
      config: {
        temperature: 0.7,
        topP: 0.8,
      }
    });
    // Use .text property to access generated content.
    return response.text || "Diagnostic data unavailable. A technician will perform a physical inspection on arrival.";
  } catch (error) {
    console.error("Gemini diagnosis failed", error);
    return "Technician will perform live diagnosis upon arrival.";
  }
};

