          {/* Desktop Navigation Links */}
          <div className="hidden xl:flex items-center space-x-6 2xl:space-x-10">
            {navLinks.map((link) => (
              <button 
                key={link.id}
                onClick={() => onNavigate(link.id)} 
                className={`text-[11px] 2xl:text-xs font-black uppercase tracking-widest transition-colors whitespace-nowrap ${currentPage === link.id ? 'text-blue-500' : 'text-zinc-500 hover:text-white'}`}
              >
                {link.label}
              </button>
            ))}
          </div>

          {/* Right Section: Language, Profile, Logout and Mobile Toggle */}
          <div className="flex items-center gap-2 sm:gap-4">
            {/* Multi-Language Dropdown */}
            <div className="relative" ref={langRef}>
              <button 
                onClick={() => setIsLangOpen(!isLangOpen)} 
                className="flex items-center gap-2 bg-zinc-900 border border-zinc-800 px-3 sm:px-4 py-2 rounded-xl text-xs font-black transition-all hover:bg-zinc-800"
              >
                <span className="text-lg">{currentLangObj.flag}</span>
                <span className="hidden md:inline text-zinc-400 uppercase tracking-tighter">{currentLangObj.id}</span>
                <i className="fa-solid fa-chevron-down text-[8px] text-zinc-600"></i>
              </button>

              {isLangOpen && (
                <div className="absolute top-full right-0 mt-3 w-48 bg-zinc-900 border border-zinc-800 rounded-2xl shadow-3xl py-2 animate-in slide-in-from-top-2 overflow-hidden">
                  {languages.map(l => (
                    <button 
                      key={l.id} 
                      onClick={() => { setLang(l.id); setIsLangOpen(false); }} 
                      className={`w-full flex items-center gap-3 px-5 py-3 text-xs font-black transition-colors ${lang === l.id ? 'text-blue-500 bg-blue-500/5' : 'text-zinc-400 hover:text-white hover:bg-zinc-800'}`}
                    >
                      <span className="text-base">{l.flag}</span>
                      <span>{l.label}</span>
                    </button>
                  ))}
                </div>
              )}
            </div>

            {/* Profile / Login */}
            {user ? (
              <div className="flex items-center gap-2 sm:gap-3">
                <button 
                  onClick={() => onNavigate('profile')} 
                  className="w-10 h-10 sm:w-12 sm:h-12 rounded-xl sm:rounded-2xl border-2 border-zinc-800 overflow-hidden hover:border-blue-500 transition-all active:scale-95 shadow-2xl relative group"
                >
                  <img 
                    src={user.avatar || `https://ui-avatars.com/api/?name=${user.name}&background=18181b&color=3b82f6`} 
                    alt="profile" 
                    className="w-full h-full object-cover group-hover:scale-110 transition-transform" 
                  />
                </button>
                {/* Desktop Logout Button */}
                <button 
                  onClick={onLogout}
                  title={t.logout}
                  className="hidden md:flex w-10 h-10 bg-zinc-900 border border-zinc-800 rounded-xl items-center justify-center text-zinc-500 hover:text-red-500 hover:border-red-500/30 transition-all active:scale-90"
                >
                  <i className="fa-solid fa-right-from-bracket"></i>
                </button>
              </div>
            ) : (
              <button 
                onClick={() => onNavigate('login')} 
                className="hidden md:block bg-blue-600 hover:bg-blue-700 text-white px-6 sm:px-8 py-3 sm:py-3.5 rounded-xl sm:rounded-2xl text-xs font-black shadow-2xl shadow-blue-600/30 active:scale-95 transition-all"
              >
                {t.signIn}
              </button>
            )}

            {/* Mobile Menu Toggle (3 Bars / X) */}
            <button 
              ref={mobileToggleRef}
              onClick={toggleMobileMenu}
              className="xl:hidden w-10 h-10 bg-zinc-900 border border-zinc-800 rounded-xl flex items-center justify-center text-zinc-400 hover:text-white transition-all active:scale-90"
            >
              <i className={`fa-solid ${isMobileMenuOpen ? 'fa-xmark' : 'fa-bars'} text-lg`}></i>
            </button>
          </div>
        </div>
      </div>

      {/* Mobile Menu Dropdown */}
      {isMobileMenuOpen && (
        <div 
          ref={mobileMenuRef}
          className="xl:hidden absolute top-20 left-0 right-0 bg-zinc-950/95 backdrop-blur-2xl border-b border-zinc-900 shadow-3xl animate-in slide-in-from-top-5 duration-300 overflow-hidden z-[90]"
        >
          <div className="flex flex-col p-4 space-y-1 max-h-[80vh] overflow-y-auto">
            {navLinks.map((link) => (
              <button 
                key={link.id}
                onClick={() => handleMobileNav(link.id)} 
                className={`w-full text-left px-6 py-4 rounded-xl text-sm font-black uppercase tracking-widest ${currentPage === link.id ? 'bg-blue-600/10 text-blue-500' : 'text-zinc-400 hover:bg-zinc-900/50'}`}
              >
                {link.label}
              </button>
            ))}

            {user ? (
              <button 
                onClick={handleLogout} 
                className="w-full text-left px-6 py-4 rounded-xl text-sm font-black uppercase tracking-widest text-red-500 hover:bg-red-500/10 transition-colors border-t border-zinc-900 mt-2 pt-4"
              >
                <i className="fa-solid fa-right-from-bracket mr-3 ml-3"></i>
                {t.logout}
              </button>
            ) : (
              <button 
                onClick={() => handleMobileNav('login')} 
                className="w-full bg-blue-600 text-white py-4 rounded-xl text-sm font-black uppercase tracking-widest mt-4"
              >
                {t.signIn}
              </button>
            )}
          </div>
        </div>
      )}
    </nav>
  );
};

export default Navbar;

import React, { useState, useEffect } from 'react';
import { User, ServiceRequest, RequestStatus } from '../types';
import { db } from '../services/db';

interface TechDashboardProps {
  user: User;
}

const TechDashboard: React.FC<TechDashboardProps> = ({ user }) => {
  const [requests, setRequests] = useState<ServiceRequest[]>([]);
  const [notifiedArrival, setNotifiedArrival] = useState<Record<string, boolean>>({});

  useEffect(() => {
    const fetchRequests = () => {
      const all = db.getRequests();
      setRequests(all.filter(r => r.technicianId === user.id).reverse());
    };
    fetchRequests();
    const interval = setInterval(fetchRequests, 5000);
    return () => clearInterval(interval);
  }, [user.id]);

  const updateStatus = (id: string, newStatus: RequestStatus) => {
    db.updateRequest(id, { status: newStatus });
    const all = db.getRequests();
    setRequests(all.filter(r => r.technicianId === user.id).reverse());
  };

  const handleNotifyArrival = (reqId: string) => {
    setNotifiedArrival(prev => ({ ...prev, [reqId]: true }));
  };

  const currentJobs = requests.filter(r => r.status !== RequestStatus.COMPLETED);
  const completedCount = requests.filter(r => r.status === RequestStatus.COMPLETED).length;

  return (
    <div className="max-w-4xl mx-auto px-4 py-12 animate-in fade-in duration-700 pb-32">
      {/* Tech Status Header */}
      <div className="bg-zinc-900 border border-zinc-800 rounded-[3rem] p-10 mb-12 flex flex-col md:flex-row justify-between items-center gap-8 shadow-2xl relative overflow-hidden">
        <div className="absolute top-0 right-0 p-4">
           <span className="flex h-3 w-3">
             <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-emerald-400 opacity-75"></span>
             <span className="relative inline-flex rounded-full h-3 w-3 bg-emerald-500"></span>
           </span>
        </div>

        <div className="flex items-center gap-8">
          <div className="w-24 h-24 rounded-[2rem] bg-zinc-950 border border-zinc-800 flex items-center justify-center text-4xl text-blue-500 relative">
             {user.avatar ? (
                <img src={user.avatar} className="w-full h-full object-cover rounded-[2rem]" alt="Avatar" />
             ) : (
                <i className="fa-solid fa-user-gear"></i>
             )}
             <div className="absolute -bottom-2 -right-2 bg-blue-600 w-8 h-8 rounded-xl flex items-center justify-center text-white text-xs border-4 border-zinc-900">
                <i className="fa-solid fa-check"></i>
             </div>
          </div>
          <div>
            <h1 className="text-4xl font-black font-brand tracking-tighter text-white">{user.name}</h1>
            <div className="flex items-center gap-4 mt-3">
              <span className="px-3 py-1 bg-emerald-500/10 text-emerald-500 text-[9px] font-black uppercase tracking-widest rounded-lg border border-emerald-500/20">System Online</span>
              <span className="text-zinc-500 text-[10px] font-black uppercase tracking-widest">Zone Delta-44</span>
            </div>
          </div>
        </div>

        <div className="grid grid-cols-2 gap-10 text-right">
          <div>
            <div className="text-[10px] text-zinc-600 font-black uppercase tracking-widest mb-1">Today's Jobs</div>
            <div className="text-3xl font-black text-white">{completedCount}</div>
          </div>
          <div>
            <div className="text-[10px] text-zinc-600 font-black uppercase tracking-widest mb-1">Performance</div>
            <div className="text-3xl font-black text-amber-500">5.0 <i className="fa-solid fa-star text-xs"></i></div>
          </div>
        </div>
      </div>

      <div className="space-y-10">
        <div className="flex justify-between items-center px-4">
           <h2 className="text-2xl font-black font-brand tracking-tight">Deployment Queue</h2>
           <span className="text-[10px] font-black text-zinc-500 uppercase tracking-widest">{currentJobs.length} MISSIONS ACTIVE</span>
        </div>

        {requests.length === 0 ? (
          <div className="bg-zinc-900 border border-zinc-800 rounded-[3rem] p-32 text-center group transition-all hover:bg-zinc-900/50">
            <div className="w-24 h-24 bg-zinc-950 rounded-[2rem] flex items-center justify-center mx-auto mb-8 border border-zinc-800 group-hover:rotate-12 transition-transform">
               <i className="fa-solid fa-satellite-dish text-zinc-800 text-4xl"></i>
            </div>
            <p className="text-zinc-500 font-black uppercase tracking-widest text-sm">Awaiting Dispatch Orders...</p>
          </div>
        ) : (
          requests.map(req => (
            <div key={req.id} className="bg-zinc-900 border border-zinc-800 rounded-[3rem] overflow-hidden shadow-2xl transition-all hover:border-zinc-700 animate-in slide-in-from-bottom-10 duration-500">
              <div className="p-10 space-y-10">
                <div className="flex justify-between items-start">
                   <div className="flex items-center gap-5">
                      <div className="w-16 h-16 bg-blue-600 rounded-[1.5rem] flex items-center justify-center text-white text-2xl shadow-xl shadow-blue-600/20">
                         <i className="fa-solid fa-truck-pickup"></i>
                      </div>
                      <div>
                         <div className="text-[10px] font-black uppercase text-zinc-600 tracking-widest mb-1">Mission Identifier</div>
                         <div className="text-2xl font-black text-white uppercase font-mono tracking-tighter">#{req.id.toUpperCase()}</div>
                      </div>
                   </div>
                   <div className={`px-5 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest border ${req.status === RequestStatus.COMPLETED ? 'border-emerald-500/20 text-emerald-500' : 'border-blue-500/20 text-blue-500'}`}>
                      {req.status}
                   </div>
                </div>

                <div className="grid md:grid-cols-2 gap-8">
                  <div className="bg-zinc-950 p-8 rounded-[2rem] border border-zinc-800">
                    <div className="text-[10px] font-black uppercase text-zinc-600 tracking-widest mb-4">Target Intel</div>
                    <div className="text-2xl font-black text-white mb-1">{req.customerName}</div>
                    <div className="text-sm text-blue-500 font-bold uppercase tracking-widest">{req.vehicleInfo}</div>
                  </div>
                  <div className="bg-zinc-950 p-8 rounded-[2rem] border border-zinc-800 relative group overflow-hidden">
                    <div className="text-[10px] font-black uppercase text-zinc-600 tracking-widest mb-4">Route Info</div>
                    <div className="text-lg font-bold text-white mb-4 truncate">{req.location}</div>
                    <button className="bg-zinc-900 hover:bg-zinc-800 text-white px-6 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest flex items-center gap-3 transition-all">
                       <i className="fa-solid fa-location-arrow text-blue-500"></i> Open Navigator
                    </button>
                  </div>
                </div>

                <div className="bg-blue-600/5 p-8 rounded-[2.5rem] border border-blue-500/20 relative overflow-hidden">
                  <div className="absolute top-0 right-0 p-8 opacity-5">
                    <i className="fa-solid fa-brain text-7xl"></i>
                  </div>
                  <div className="flex items-center gap-3 mb-4 text-blue-500">
                    <i className="fa-solid fa-clipboard-check"></i>
                    <span className="text-[11px] font-black uppercase tracking-widest">Smart Diagnostic Audit</span>
                  </div>
                  <p className="text-zinc-300 text-sm italic leading-relaxed font-medium">
                    "{req.aiDiagnosis}"
                  </p>
                </div>

                {/* Mission Control Actions */}
                <div className="flex flex-col md:flex-row gap-5 pt-4">
                  {req.status === RequestStatus.ASSIGNED && (
                    <button 
                      onClick={() => updateStatus(req.id, RequestStatus.IN_PROGRESS)}
                      className="flex-1 bg-blue-600 hover:bg-blue-700 text-white font-black py-6 rounded-[1.5rem] shadow-2xl shadow-blue-600/30 transition-all active:scale-95 text-xl relative group overflow-hidden"
                    >
                      <div className="absolute inset-0 bg-white/10 translate-x-[-100%] group-hover:translate-x-[100%] transition-transform duration-1000"></div>
                      Acknowledge & Start
                    </button>
                  )}

                  {req.status === RequestStatus.IN_PROGRESS && (
                    <>
                      <button 
                        onClick={() => updateStatus(req.id, RequestStatus.COMPLETED)}
                        className="flex-[2] bg-emerald-600 hover:bg-emerald-700 text-white font-black py-6 rounded-[1.5rem] shadow-2xl shadow-emerald-600/30 transition-all active:scale-95 text-xl"
                      >
                        Finish Repair Mission
                      </button>
                      <button 
                        onClick={() => handleNotifyArrival(req.id)}
                        disabled={notifiedArrival[req.id]}
                        className={`flex-1 ${notifiedArrival[req.id] ? 'bg-zinc-800 text-emerald-500 border-emerald-500/20' : 'bg-zinc-800 hover:bg-zinc-700 text-white border-zinc-700'} font-black py-6 rounded-[1.5rem] border transition-all active:scale-95 text-lg`}
                      >
                        {notifiedArrival[req.id] ? 'Customer Notified' : 'Arrival Signal'}
                      </button>
                    </>
                  )}

                  {req.status === RequestStatus.COMPLETED && (
                    <div className="w-full bg-emerald-500/10 text-emerald-500 text-center py-8 rounded-[1.5rem] border border-emerald-500/20 font-black uppercase tracking-widest text-lg animate-in zoom-in">
                      <i className="fa-solid fa-circle-check mr-3"></i> Mission Success • Session Logged
                    </div>
                  )}
                </div>
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
};

export default TechDashboard;

import React, { useState, useRef, useEffect } from 'react';
import { User, UserRole } from '../types';
import { translations, Language } from '../translations';

interface NavbarProps {
  user: User | null;
  onLogout: () => void;
  onNavigate: (page: string) => void;
  currentPage: string;
  lang: Language;
  setLang: (lang: Language) => void;
}

const Navbar: React.FC<NavbarProps> = ({ user, onLogout, onNavigate, currentPage, lang, setLang }) => {
  const [isLangOpen, setIsLangOpen] = useState(false);
  const [isNotifOpen, setIsNotifOpen] = useState(false);
  const [isDarkMode, setIsDarkMode] = useState(true);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  const langRef = useRef<HTMLDivElement>(null);
  const notifRef = useRef<HTMLDivElement>(null);
  const mobileMenuRef = useRef<HTMLDivElement>(null);
  const mobileToggleRef = useRef<HTMLButtonElement>(null);

  const t = translations[lang].nav;

  const mockNotifications = [
    { id: 1, text: lang === 'ar' ? 'تم قبول طلب الصيانة الخاص بك' : 'Service request accepted', time: '2m ago', icon: 'fa-check-circle', color: 'text-emerald-500' },
    { id: 2, text: lang === 'ar' ? 'الفني "جون" في الطريق إليك' : 'Tech "John" is en-route', time: '15m ago', icon: 'fa-truck-fast', color: 'text-blue-500' },
    { id: 3, text: lang === 'ar' ? 'عرض خاص: خصم 15% لمشتركي برو' : 'PRO Offer: 15% off parts', time: '1h ago', icon: 'fa-gem', color: 'text-amber-500' },
  ];

  const languages: { id: Language; label: string; flag: string }[] = [
    { id: 'en', label: 'English', flag: '🇺🇸' },
    { id: 'ar', label: 'العربية', flag: '🇪🇬' },
    { id: 'fr', label: 'Français', flag: '🇫🇷' },
    { id: 'de', label: 'Deutsch', flag: '🇩🇪' },
    { id: 'es', label: 'Español', flag: '🇪🇸' },
  ];

  const navLinks = [
    { id: 'home', label: t.home },
    { id: 'services', label: t.services },
    { id: 'pro', label: t.pro },
    { id: 'coverage', label: t.coverage },
    { id: 'fleet', label: lang === 'ar' ? 'الأساطيل' : 'Fleet' },
    { id: 'careers', label: t.careers },
    { id: 'about', label: t.about },
    { id: 'contact', label: lang === 'ar' ? 'اتصل بنا' : 'Contact' },
  ];

  const currentLangObj = languages.find(l => l.id === lang) || languages[0];

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (langRef.current && !langRef.current.contains(event.target as Node)) setIsLangOpen(false);
      if (notifRef.current && !notifRef.current.contains(event.target as Node)) setIsNotifOpen(false);
      if (
        mobileMenuRef.current && 
        !mobileMenuRef.current.contains(event.target as Node) && 
        mobileToggleRef.current && 
        !mobileToggleRef.current.contains(event.target as Node)
      ) {
        setIsMobileMenuOpen(false);
      }
    };

    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const toggleTheme = () => {
    setIsDarkMode(!isDarkMode);
    document.body.classList.toggle('light-mode');
  };

  const handleMobileNav = (page: string) => {
    onNavigate(page);
    setIsMobileMenuOpen(false);
  };

  const handleLogout = () => {
    onLogout();
    setIsMobileMenuOpen(false);
  };

  return (
    <nav className="fixed top-0 left-0 right-0 w-full z-[100] bg-zinc-950/80 backdrop-blur-xl border-b border-zinc-900 shadow-2xl transition-colors duration-400">
      <div className="max-w-[1600px] mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex items-center justify-between h-20">
          {/* Logo */}
          <div className="flex items-center shrink-0">
            <button onClick={() => onNavigate('home')} className="flex items-center gap-2 group">
              <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center transform group-hover:rotate-12 transition-transform shadow-lg shadow-blue-600/20">
                <i className="fa-solid fa-bolt-lightning text-white"></i>
              </div>
              <span className="font-brand text-2xl font-black tracking-tighter text-white">
                Auto<span className="text-blue-500">Go</span>
              </span>
            </button>
          </div>

          {/* Desktop Navigation Links */}
          <div className="hidden xl:flex items-center space-x-6 2xl:space-x-10">
            {navLinks.map((link) => (
              <button 
                key={link.id}
                onClick={() => onNavigate(link.id)} 
                className={`text-[11px] 2xl:text-xs font-black uppercase tracking-widest transition-colors whitespace-nowrap ${currentPage === link.id ? 'text-blue-500' : 'text-zinc-500 hover:text-white'}`}
              >
                {link.label}
              </button>
            ))}
          </div>

          {/* Right Section Tools */}
          <div className="flex items-center gap-2 sm:gap-4">

            {/* Theme Toggle */}
            <button 
              onClick={toggleTheme}
              className="w-10 h-10 bg-zinc-900 border border-zinc-800 rounded-xl flex items-center justify-center text-zinc-400 hover:text-blue-500 transition-all active:scale-90"
              title={isDarkMode ? 'Switch to Light Mode' : 'Switch to Dark Mode'}
            >
              <i className={`fa-solid ${isDarkMode ? 'fa-sun' : 'fa-moon'} text-lg`}></i>
            </button>

            {/* Notifications */}
            {user && (
              <div className="relative" ref={notifRef}>
                <button 
                  onClick={() => setIsNotifOpen(!isNotifOpen)}
                  className="w-10 h-10 bg-zinc-900 border border-zinc-800 rounded-xl flex items-center justify-center text-zinc-400 hover:text-blue-500 transition-all active:scale-90 relative"
                >
                  <i className="fa-solid fa-bell text-lg"></i>
                  <span className="absolute top-2 right-2 w-2 h-2 bg-red-500 rounded-full border border-zinc-950"></span>
                </button>

                {isNotifOpen && (
                  <div className="absolute top-full right-0 mt-3 w-80 bg-zinc-900 border border-zinc-800 rounded-2xl shadow-3xl py-4 animate-in slide-in-from-top-2 z-[110]">
                    <div className="px-5 pb-3 border-b border-zinc-800 flex justify-between items-center">
                      <span className="text-xs font-black uppercase tracking-widest text-white">{lang === 'ar' ? 'التنبيهات' : 'Notifications'}</span>
                      <button className="text-[10px] text-blue-500 font-bold hover:underline">{lang === 'ar' ? 'تحديد الكل كمقروء' : 'Clear All'}</button>
                    </div>
                    <div className="max-h-64 overflow-y-auto">
                      {mockNotifications.map(notif => (
                        <div key={notif.id} className="px-5 py-4 hover:bg-zinc-800/50 transition-colors flex gap-4 border-b border-zinc-800/50 last:border-0">
                          <i className={`fa-solid ${notif.icon} ${notif.color} mt-1`}></i>
                          <div>
                            <p className="text-xs font-bold text-zinc-300 leading-tight mb-1">{notif.text}</p>
                            <span className="text-[9px] text-zinc-600 font-black uppercase tracking-tighter">{notif.time}</span>
                          </div>
                        </div>
                      ))}
                    </div>
                  </div>
                )}
              </div>
            )}

            {/* Language Selector */}
            <div className="relative" ref={langRef}>
              <button 
                onClick={() => setIsLangOpen(!isLangOpen)} 
                className="flex items-center gap-2 bg-zinc-900 border border-zinc-800 px-3 sm:px-4 py-2 rounded-xl text-xs font-black transition-all hover:bg-zinc-800"
              >
                <span className="text-lg">{currentLangObj.flag}</span>
                <span className="hidden md:inline text-zinc-400 uppercase tracking-tighter">{currentLangObj.id}</span>
              </button>

              {isLangOpen && (
                <div className="absolute top-full right-0 mt-3 w-48 bg-zinc-900 border border-zinc-800 rounded-2xl shadow-3xl py-2 animate-in slide-in-from-top-2 overflow-hidden z-[110]">
                  {languages.map(l => (
                    <button 
                      key={l.id} 
                      onClick={() => { setLang(l.id); setIsLangOpen(false); }} 
                      className={`w-full flex items-center gap-3 px-5 py-3 text-xs font-black transition-colors ${lang === l.id ? 'text-blue-500 bg-blue-500/5' : 'text-zinc-400 hover:text-white hover:bg-zinc-800'}`}
                    >
                      <span className="text-base">{l.flag}</span>
                      <span>{l.label}</span>
                    </button>
                  ))}
                </div>
              )}
            </div>

            {/* Profile Section */}
            {user ? (
              <div className="flex items-center gap-2">
                <button 
                  onClick={() => onNavigate('profile')} 
                  className="w-10 h-10 sm:w-12 sm:h-12 rounded-xl border-2 border-zinc-800 overflow-hidden hover:border-blue-500 transition-all active:scale-95 shadow-2xl relative group"
                >
                  <img 
                    src={user.avatar || `https://ui-avatars.com/api/?name=${user.name}&background=18181b&color=3b82f6`} 
                    alt="profile" 
                    className="w-full h-full object-cover group-hover:scale-110 transition-transform" 
                  />
                </button>
                <button 
