interface SignupProps {
  onLogin: (user: User) => void;
  onNavigate: (page: string) => void;
  lang?: Language;
}

const Signup: React.FC<SignupProps> = ({ onLogin, onNavigate, lang = 'en' }) => {
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    password: '',
    role: UserRole.CUSTOMER
  });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const authT = translations[lang].auth;

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    const cleanEmail = formData.email.trim();
    await new Promise(resolve => setTimeout(resolve, 1500));

    try {
      const user = db.registerUser({
        name: formData.name,
        email: cleanEmail,
        role: formData.role
      });

      notificationService.notifyAdminOnRegistration(user).catch(() => {});
      db.setCurrentUser(user);
      onLogin(user);
    } catch (err: any) {
      setError('System unavailable. Please try again.');
      setLoading(false);
