import React, { useState, useEffect } from 'react';
import { User, UserRole } from './types';
import { db } from './services/db';
import Navbar from './components/Navbar';
import Home from './pages/Home';
import Login from './pages/Login';
import Signup from './pages/Signup';
import RequestService from './pages/RequestService';
import CustomerDashboard from './pages/CustomerDashboard';
import AdminDashboard from './pages/AdminDashboard';
import TechDashboard from './pages/TechDashboard';
import Careers from './pages/Careers';
import About from './pages/About';
import Contact from './pages/Contact';
import ServicesPage from './pages/ServicesPage';
import ProPlans from './pages/ProPlans';
import Coverage from './pages/Coverage';
import PrivacyPolicy from './pages/PrivacyPolicy';
import TermsOfService from './pages/TermsOfService';
import FleetSales from './pages/FleetSales';
import Payment from './pages/Payment';
import Profile from './pages/Profile';
import Footer from './components/Footer';
import LoadingScreen from './components/LoadingScreen';
import { translations, Language } from './translations';

const App: React.FC = () => {
  const [currentPage, setCurrentPage] = useState<string>('home');
  const [selectedPlan, setSelectedPlan] = useState<any>(null);
  const [user, setUser] = useState<User | null>(null);
  const [lang, setLang] = useState<Language>('en');
  const [isInitialLoading, setIsInitialLoading] = useState(true);

  useEffect(() => {
    db.init();
    const savedUser = db.getCurrentUser();
    if (savedUser) setUser(savedUser);

    const timer = setTimeout(() => {
      setIsInitialLoading(false);
    }, 1200);

    return () => clearTimeout(timer);
  }, []);

  useEffect(() => {
    document.documentElement.dir = lang === 'ar' ? 'rtl' : 'ltr';
    document.documentElement.lang = lang;
  }, [lang]);

  useEffect(() => {
    window.scrollTo({ top: 0, behavior: 'smooth' });
  }, [currentPage]);

  const handleLogout = () => {
    db.setCurrentUser(null);
    setUser(null);
    setCurrentPage('home');
  };

  const handleUpdateUser = (updatedUser: User) => {
    setUser(updatedUser);
  };

  const navigateToPayment = (plan: any) => {
    if (!user) {
      setCurrentPage('login');
      return;
    }
    setSelectedPlan(plan);
    setCurrentPage('payment');
  };

  const renderPage = () => {
    switch (currentPage) {
      case 'home': return <Home onNavigate={setCurrentPage} lang={lang} />;
      case 'login': return <Login onLogin={(u) => { setUser(u); setCurrentPage('dashboard'); }} onNavigate={setCurrentPage} lang={lang} />;
      case 'signup': return <Signup onLogin={(u) => { setUser(u); setCurrentPage('dashboard'); }} onNavigate={setCurrentPage} lang={lang} />;
      case 'services': return <ServicesPage onNavigate={setCurrentPage} lang={lang} />;
      case 'coverage': return <Coverage />;
      case 'request': return user ? <RequestService user={user} onComplete={() => setCurrentPage('dashboard')} lang={lang} /> : <Login onLogin={(u) => { setUser(u); setCurrentPage('request'); }} onNavigate={setCurrentPage} lang={lang} />;
      case 'dashboard': 
        if (!user) return <Login onLogin={(u) => { setUser(u); setCurrentPage('dashboard'); }} onNavigate={setCurrentPage} lang={lang} />;
        if (user.role === UserRole.ADMIN) return <AdminDashboard />;
        if (user.role === UserRole.TECHNICIAN) return <TechDashboard user={user} />;
        return <CustomerDashboard user={user} onNavigate={setCurrentPage} />;
      case 'profile': return user ? <Profile user={user} onUpdate={handleUpdateUser} lang={lang} /> : <Login onLogin={(u) => { setUser(u); setCurrentPage('profile'); }} onNavigate={setCurrentPage} lang={lang} />;
      case 'careers': return <Careers />;
      case 'about': return <About />;
      case 'contact': return <Contact lang={lang} />;
      case 'pro': return <ProPlans onSubscribe={navigateToPayment} />;
      case 'payment': return <Payment plan={selectedPlan} user={user!} lang={lang} onComplete={() => setCurrentPage('dashboard')} />;
      case 'privacy': return <PrivacyPolicy />;
      case 'terms': return <TermsOfService />;
      case 'fleet': return <FleetSales onNavigate={setCurrentPage} />;
      default: return <Home onNavigate={setCurrentPage} lang={lang} />;
    }
  };

  if (isInitialLoading) {
    return <LoadingScreen />;
  }

  return (
    <div className={`min-h-screen flex flex-col bg-zinc-950 text-zinc-100 animate-in fade-in duration-700 ${lang === 'ar' ? 'font-arabic' : ''}`}>
      <Navbar 
        user={user} 
        onLogout={handleLogout} 
        onNavigate={onNavigate => setCurrentPage(onNavigate)} 
        currentPage={currentPage}
        lang={lang}
        setLang={setLang}
      />
      <main className="flex-grow pt-20">
        {renderPage()}
      </main>
      <Footer onNavigate={setCurrentPage} lang={lang} />
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { User, ServiceRequest, RequestStatus } from '../types';
import { db } from '../services/db';

interface CustomerDashboardProps {
  user: User;
  onNavigate: (page: string) => void;
}

const CustomerDashboard: React.FC<CustomerDashboardProps> = ({ user, onNavigate }) => {
  const [requests, setRequests] = useState<ServiceRequest[]>([]);
  const [selectedReq, setSelectedReq] = useState<ServiceRequest | null>(null);
  const [isCalling, setIsCalling] = useState(false);
  const [isChatOpen, setIsChatOpen] = useState(false);
  const [callTimer, setCallTimer] = useState(0);

  // Chat State
  const [chatMessages, setChatMessages] = useState([
    { sender: 'tech', text: 'Hello! I am on my way to your location.', time: '2m ago' }
  ]);
  const [newMessage, setNewMessage] = useState('');
  const chatEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const fetchRequests = () => {
      const all = db.getRequests();
      setRequests(all.filter(r => r.customerId === user.id).reverse());
    };
    fetchRequests();
    const interval = setInterval(fetchRequests, 5000);
    return () => clearInterval(interval);
  }, [user.id]);

  useEffect(() => {
    let interval: any;
    if (isCalling) {
      interval = setInterval(() => setCallTimer(prev => prev + 1), 1000);
    } else {
      setCallTimer(0);
    }
    return () => clearInterval(interval);
  }, [isCalling]);

  useEffect(() => {
    if (isChatOpen) {
      chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
    }
  }, [chatMessages, isChatOpen]);

  const activeRequest = requests.find(r => r.status === RequestStatus.ASSIGNED || r.status === RequestStatus.IN_PROGRESS);

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  const handleSendMessage = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newMessage.trim()) return;

    const msg = { sender: 'user', text: newMessage, time: 'Just now' };
    setChatMessages([...chatMessages, msg]);
    setNewMessage('');

    // Simulate tech response after 1.5s
    setTimeout(() => {
      setChatMessages(prev => [...prev, { 
        sender: 'tech', 
        text: 'Received! Checking your location details now.', 
        time: 'Just now' 
      }]);
    }, 1500);
  };

  const getStatusStyle = (status: RequestStatus) => {
    switch (status) {
      case RequestStatus.PENDING: return 'text-amber-500 bg-amber-500/10 border-amber-500/20';
      case RequestStatus.ASSIGNED: return 'text-blue-500 bg-blue-500/10 border-blue-500/20';
      case RequestStatus.IN_PROGRESS: return 'text-indigo-500 bg-indigo-500/10 border-indigo-500/20';
      case RequestStatus.COMPLETED: return 'text-emerald-500 bg-emerald-500/10 border-emerald-500/20';
      default: return 'text-zinc-500 bg-zinc-500/10 border-zinc-800';
    }
  };

  return (
    <div className="max-w-7xl mx-auto px-4 py-8 animate-in fade-in duration-700">
      {/* Dynamic Header */}
      <div className="flex flex-col md:flex-row justify-between items-end gap-6 mb-12">
        <div>
          <h1 className="text-4xl md:text-6xl font-black font-brand text-white tracking-tighter">
            Control <span className="text-blue-500">Center</span>
          </h1>
          <p className="text-zinc-500 text-lg mt-2 font-medium">Hello, {user.name.split(' ')[0]}! Your fleet is under protection.</p>
        </div>
        <button 
          onClick={() => onNavigate('request')}
