                  <div className="flex items-center gap-4">
                    <div className={`w-12 h-12 rounded-xl bg-zinc-900 border border-zinc-800 flex items-center justify-center transition-colors ${
                      email.toLowerCase() === (role.id === UserRole.ADMIN ? 'admin@autogo.com' : role.id === UserRole.TECHNICIAN ? 'tech@autogo.com' : 'mohamed@autogo.com')
                      ? 'text-blue-500 border-blue-500/30' : 'text-zinc-500 group-hover:text-inherit'
                    }`}>
                      <i className={`fa-solid ${role.icon} text-lg`}></i>
                    </div>
                    <div className="text-left">
                      <div className="text-sm font-black text-white group-hover:translate-x-1 transition-transform">{role.title}</div>
                      <div className="text-[9px] text-zinc-600 font-black uppercase tracking-widest">{lang === 'ar' ? 'اختيار الرتبة' : 'Select Role'}</div>
                    </div>
                  </div>
                  {email.toLowerCase() === (role.id === UserRole.ADMIN ? 'admin@autogo.com' : role.id === UserRole.TECHNICIAN ? 'tech@autogo.com' : 'mohamed@autogo.com') && (
                    <i className="fa-solid fa-circle-check text-blue-500 animate-in zoom-in"></i>
                  )}
                </button>
              ))}
            </div>
          </div>

          {/* Login Form Side */}
          <div className="flex flex-col justify-center">
            <div className="text-center md:text-left mb-8">
              <h2 className="text-3xl font-black font-brand text-white tracking-tighter">Security <span className="text-emerald-500">Check</span></h2>
              <p className="text-zinc-500 text-sm font-medium">Enter password to authorize access</p>
            </div>

            <form onSubmit={handleSubmit} className="space-y-6">
              {error && (
                <div className="bg-red-500/10 border border-red-500/20 text-red-500 p-4 rounded-xl text-xs font-bold flex items-center gap-2 animate-shake">
                  <i className="fa-solid fa-circle-exclamation"></i>
                  {error}
                </div>
              )}

              <div>
                <label className="block text-[10px] font-black uppercase tracking-widest text-zinc-600 mb-2 ml-1">Identity (Email)</label>
                <input 
                  type="email" 
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  className={`w-full bg-zinc-950 border border-zinc-800 rounded-xl px-4 py-4 focus:ring-2 focus:ring-blue-500 outline-none transition-all text-white text-sm ${lang === 'ar' ? 'text-right' : ''}`}
                  placeholder="name@example.com"
                  required
                />
              </div>

              <div className="relative">
                <label className="block text-[10px] font-black uppercase tracking-widest text-zinc-600 mb-2 ml-1">Access Key (Password)</label>
                <input 
                  ref={passwordInputRef}
                  type="password" 
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  className={`w-full bg-zinc-950 border border-zinc-800 rounded-xl px-4 py-4 focus:ring-2 focus:ring-blue-500 outline-none transition-all text-white text-sm ${lang === 'ar' ? 'text-right' : ''}`}
                  placeholder="••••••••"
                  required
                />

                {selectedRoleHint && (
                  <div className="mt-3 p-3 bg-blue-600/10 border border-blue-500/20 rounded-xl flex items-center justify-between animate-in slide-in-from-top-2">
                    <span className="text-[10px] text-blue-400 font-bold uppercase tracking-widest">Hint: {selectedRoleHint}</span>
                    <button 
                      type="button" 
                      onClick={() => setPassword(selectedRoleHint)}
                      className="text-[9px] bg-blue-600 text-white px-2 py-1 rounded-md font-black hover:bg-blue-700 transition-colors"
                    >
                      AUTO-FILL
                    </button>
                  </div>
                )}
              </div>

              <button 
                type="submit"
                disabled={isLoading}
                className="w-full bg-blue-600 hover:bg-blue-700 disabled:opacity-50 text-white font-black py-5 rounded-xl transition-all shadow-xl shadow-blue-600/20 active:scale-95 text-lg mt-4 flex items-center justify-center gap-3"
              >
                {isLoading ? (
                  <>
                    <div className="w-5 h-5 border-2 border-white/20 border-t-white rounded-full animate-spin"></div>
                    <span>Verifying...</span>
                  </>
                ) : (
                  <>
                    <i className="fa-solid fa-shield-check"></i>
                    <span>Authorize Login</span>
                  </>
                )}
              </button>
            </form>

            <div className="mt-8 text-center">
              <p className="text-zinc-500 text-xs">
                {lang === 'ar' ? 'مستخدم جديد؟' : "New operative?"} <button onClick={() => onNavigate('signup')} className="text-blue-500 font-bold hover:underline">{lang === 'ar' ? 'انضم للأسطول' : 'Join the Fleet'}</button>
              </p>
            </div>
          </div>

        </div>
      </div>

      {/* Background decoration */}
      <div className="fixed top-0 left-0 w-full h-full pointer-events-none -z-10 overflow-hidden">
        <div className="absolute top-1/4 left-1/4 w-[500px] h-[500px] bg-blue-600/5 rounded-full blur-[120px] animate-pulse"></div>
        <div className="absolute bottom-1/4 right-1/4 w-[400px] h-[400px] bg-emerald-600/5 rounded-full blur-[120px] animate-pulse delay-700"></div>
      </div>
    </div>
  );
};

export default Login;

import { User, UserRole, ServiceRequest, RequestStatus, JobApplication } from '../types';

const KEYS = {
  USERS: 'autogo_users',
  REQUESTS: 'autogo_requests',
  APPLICATIONS: 'autogo_applications',
  CURRENT_USER: 'autogo_current_user'
};

const DEFAULT_USERS: User[] = [
  { id: '1', name: 'Admin Operative', email: 'admin@autogo.com', role: UserRole.ADMIN },
  { id: '2', name: 'Expert Technician', email: 'tech@autogo.com', role: UserRole.TECHNICIAN },
  { id: '3', name: 'Mohamed Customer', email: 'mohamed@autogo.com', role: UserRole.CUSTOMER, isPro: true }
];

export const db = {
  init: () => {
    if (!localStorage.getItem(KEYS.USERS)) {
      localStorage.setItem(KEYS.USERS, JSON.stringify(DEFAULT_USERS));
    }
    if (!localStorage.getItem(KEYS.REQUESTS)) {
      localStorage.setItem(KEYS.REQUESTS, JSON.stringify([]));
    }
    if (!localStorage.getItem(KEYS.APPLICATIONS)) {
      localStorage.setItem(KEYS.APPLICATIONS, JSON.stringify([]));
    }
  },

  getUsers: (): User[] => {
    try {
      return JSON.parse(localStorage.getItem(KEYS.USERS) || '[]');
    } catch {
      return DEFAULT_USERS;
    }
  },

  registerUser: (userData: Omit<User, 'id'>) => {
    const users = db.getUsers();
    const existingUser = users.find(u => u.email.toLowerCase() === userData.email.toLowerCase());

    if (existingUser) {
      return existingUser;
    }

    const newUser: User = {
      ...userData,
      id: Math.random().toString(36).substr(2, 9),
    };

    users.push(newUser);
    localStorage.setItem(KEYS.USERS, JSON.stringify(users));
    return newUser;
  },

  updateUser: (id: string, updates: Partial<User>) => {
    const users = db.getUsers();
    const index = users.findIndex(u => u.id === id);
    if (index !== -1) {
      const updatedUser = { ...users[index], ...updates };
      users[index] = updatedUser;
      localStorage.setItem(KEYS.USERS, JSON.stringify(users));

      const current = db.getCurrentUser();
      if (current && current.id === id) {
        db.setCurrentUser(updatedUser);
      }
      return updatedUser;
    }
    return null;
  },

  getRequests: (): ServiceRequest[] => {
    try {
      return JSON.parse(localStorage.getItem(KEYS.REQUESTS) || '[]');
    } catch {
      return [];
    }
  },

  addRequest: (request: Omit<ServiceRequest, 'id' | 'status' | 'createdAt'>) => {
    const requests = db.getRequests();
    const newRequest: ServiceRequest = {
      ...request,
      id: 'atg-' + Math.random().toString(36).substr(2, 5),
      status: RequestStatus.PENDING,
      createdAt: new Date().toISOString()
    };
    requests.push(newRequest);
    localStorage.setItem(KEYS.REQUESTS, JSON.stringify(requests));
    return newRequest;
  },

  updateRequest: (id: string, updates: Partial<ServiceRequest>) => {
    const requests = db.getRequests();
    const index = requests.findIndex(r => r.id === id);
    if (index !== -1) {
      requests[index] = { ...requests[index], ...updates };
      localStorage.setItem(KEYS.REQUESTS, JSON.stringify(requests));
    }
  },

  addApplication: (application: Omit<JobApplication, 'id' | 'status'>) => {
    let applications: JobApplication[] = [];
    try {
      applications = JSON.parse(localStorage.getItem(KEYS.APPLICATIONS) || '[]');
    } catch {
      applications = [];
    }

    const newApplication: JobApplication = {
      ...application,
      id: 'app-' + Math.random().toString(36).substr(2, 5),
      status: 'PENDING'
    };

    applications.push(newApplication);
    localStorage.setItem(KEYS.APPLICATIONS, JSON.stringify(applications));
    return newApplication;
  },

  getCurrentUser: (): User | null => {
    const user = localStorage.getItem(KEYS.CURRENT_USER);
    return user ? JSON.parse(user) : null;
  },

  setCurrentUser: (user: User | null) => {
    if (user) localStorage.setItem(KEYS.CURRENT_USER, JSON.stringify(user));
    else localStorage.removeItem(KEYS.CURRENT_USER);
  }
};
